// Mermaid diagram placeholder
// In production, load from: https://cdn.jsdelivr.net/npm/mermaid@10/dist/mermaid.min.js
// For offline use, download and place here
window.mermaid = { initialize: function() {}, run: function() {} };
document.addEventListener('DOMContentLoaded', function() {
  document.querySelectorAll('.mermaid').forEach(function(el) {
    el.style.background = '#f0f4ff';
    el.style.padding = '1rem';
    el.style.borderRadius = '4px';
    el.style.fontFamily = 'monospace';
    el.style.whiteSpace = 'pre';
    el.style.overflowX = 'auto';
    el.setAttribute('title', 'Mermaid diagram - load mermaid.min.js for rendered view');
  });
});
